@use 'sass:map';
@use '../core/theming/theming';
@use '../core/tokens/m2-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);
  $density-scale: theming.clamp-density(map.get($system, density-scale), -3);

  @return (
    base: (),
    color: private-get-color-palette-color-tokens(
        map.get($system, surface), map.get($system, on-surface)),
    typography: (
      toolbar-title-text-font: map.get($system, title-small-font),
      toolbar-title-text-line-height: map.get($system, title-small-line-height),
      toolbar-title-text-size: map.get($system, title-small-size),
      toolbar-title-text-tracking: map.get($system, title-small-tracking),
      toolbar-title-text-weight: map.get($system, title-small-weight),
    ),
    density: (
      toolbar-standard-height: map.get((
        0: 64px,
        -1: 60px,
        -2: 56px,
        -3: 52px,
      ), $density-scale),
      toolbar-mobile-height: map.get((
        0: 56px,
        -1: 52px,
        -2: 48px,
        -3: 44px,
      ), $density-scale),
    ),
  );
}

// Generates the tokens used to theme the toolbar based on a palette.
@function private-get-color-palette-color-tokens($background-color, $text-color) {
  @return (
    toolbar-container-background-color: $background-color,
    toolbar-container-text-color: $text-color,
  );
}

// Button variants
//
// Easily pump out default styles, as well as :hover, :focus, :active,
// and disabled options for all buttons

@mixin button-variant($color, $background, $border) {
  color: $color;
  background-color: $background;
  border-color: $border;

  &:focus,
  &.focus {
    color: $color;
    background-color: darken($background, 10%);
    border-color: darken($border, 25%);
  }
  &:hover {
    color: $color;
    background-color: darken($background, 10%);
    border-color: darken($border, 12%);
  }
  &:active,
  &.active,
  .open > &.dropdown-toggle {
    color: $color;
    background-color: darken($background, 10%);
    background-image: none;
    border-color: darken($border, 12%);

    &:hover,
    &:focus,
    &.focus {
      color: $color;
      background-color: darken($background, 17%);
      border-color: darken($border, 25%);
    }
  }
  &.disabled,
  &[disabled],
  fieldset[disabled] & {
    &:hover,
    &:focus,
    &.focus {
      background-color: $background;
      border-color: $border;
    }
  }

  .badge {
    color: $background;
    background-color: $color;
  }
}

// Button sizes
@mixin button-size($padding-vertical, $padding-horizontal, $font-size, $line-height, $border-radius) {
  padding: $padding-vertical $padding-horizontal;
  font-size: $font-size;
  line-height: $line-height;
  border-radius: $border-radius;
}

// scss-docs-start caret-mixins
@mixin caret-down($width: $caret-width) {
  border-top: $width solid;
  border-right: $width solid transparent;
  border-bottom: 0;
  border-left: $width solid transparent;
}

@mixin caret-up($width: $caret-width) {
  border-top: 0;
  border-right: $width solid transparent;
  border-bottom: $width solid;
  border-left: $width solid transparent;
}

@mixin caret-end($width: $caret-width) {
  border-top: $width solid transparent;
  border-right: 0;
  border-bottom: $width solid transparent;
  border-left: $width solid;
}

@mixin caret-start($width: $caret-width) {
  border-top: $width solid transparent;
  border-right: $width solid;
  border-bottom: $width solid transparent;
}

@mixin caret(
  $direction: down,
  $width: $caret-width,
  $spacing: $caret-spacing,
  $vertical-align: $caret-vertical-align
) {
  @if $enable-caret {
    &::after {
      display: inline-block;
      margin-left: $spacing;
      vertical-align: $vertical-align;
      content: "";
      @if $direction == down {
        @include caret-down($width);
      } @else if $direction == up {
        @include caret-up($width);
      } @else if $direction == end {
        @include caret-end($width);
      }
    }

    @if $direction == start {
      &::after {
        display: none;
      }

      &::before {
        display: inline-block;
        margin-right: $spacing;
        vertical-align: $vertical-align;
        content: "";
        @include caret-start($width);
      }
    }

    &:empty::after {
      margin-left: 0;
    }
  }
}
// scss-docs-end caret-mixins

//
// Pages: Lock Screen
//

// ADD THIS CLASS TO THE <BODY> TAG
.lockscreen {
  // User name [optional]
  .lockscreen-name {
    font-weight: 600;
    text-align: center;
  }

  .lockscreen-logo {
    margin-bottom: 25px;
    font-size: 35px;
    font-weight: 300;
    text-align: center;

    a {
      color: var(--#{$prefix}emphasis-color);
      text-decoration: none;
    }
  }

  .lockscreen-wrapper {
    max-width: 400px;
    margin: 0 auto;
    margin-top: 10%;
  }

  // Will contain the image and the sign in form
  .lockscreen-item {
    position: relative;
    width: 290px;
    padding: 0;
    margin: 10px auto 30px;
    background-color: var(--#{$prefix}body-bg);
    @include border-radius(4px);
  }

  // User image
  .lockscreen-image {
    position: absolute;
    top: -25px;
    left: -10px;
    z-index: 10;
    padding: 5px;
    background-color: var(--#{$prefix}body-bg);
    @include border-radius(50%);

    > img {
      @include border-radius(50%);
      width: 70px;
      height: 70px;
    }
  }

  // Contains the password input and the login button
  .lockscreen-credentials {
    margin-left: 70px;

    .form-control {
      border: 0;
    }

    .btn {
      padding: 0 10px;
      border: 0;
    }
  }

  .lockscreen-footer {
    margin-top: 10px;
  }
}

@use '../core/style/elevation';
@use 'sass:map';
@use '../core/tokens/m2-utils';
@use '../core/tokens/m3-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (
      menu-container-shape: 4px,
      menu-divider-bottom-spacing: 0,
      menu-divider-top-spacing: 0,
      menu-item-spacing: 16px,
      menu-item-icon-size: 24px,
      menu-item-leading-spacing: 16px,
      menu-item-trailing-spacing: 16px,
      menu-item-with-icon-leading-spacing: 16px,
      menu-item-with-icon-trailing-spacing: 16px,
      menu-container-elevation-shadow: elevation.get-box-shadow(8),

      // Unused
      menu-base-elevation-level: null,
    ),
    color: (
      menu-item-label-text-color: map.get($system, on-surface),
      menu-item-icon-color: map.get($system, on-surface),
      menu-item-hover-state-layer-color: m3-utils.color-with-opacity(
          map.get($system, on-surface), map.get($system, hover-state-layer-opacity)),
      menu-item-focus-state-layer-color: m3-utils.color-with-opacity(
          map.get($system, on-surface), map.get($system, focus-state-layer-opacity)),
      menu-container-color: map.get($system, surface),
      menu-divider-color: map.get($system, outline),
    ),
    typography: (
      menu-item-label-text-font: map.get($system, body-large-font),
      menu-item-label-text-size: map.get($system, body-large-size),
      menu-item-label-text-tracking: map.get($system, body-large-tracking),
      menu-item-label-text-line-height: map.get($system, body-large-line-height),
      menu-item-label-text-weight: map.get($system, body-large-weight),
    ),
    density: (),
  );
}

@use "../utilities/initial-variables" as iv;
@use "../utilities/mixins" as mx;

$container-offset: 2 * iv.$gap !default;
$container-max-width: iv.$fullhd !default;

.#{iv.$class-prefix}container {
  flex-grow: 1;
  margin: 0 auto;
  position: relative;
  width: 100%;

  &.#{iv.$class-prefix}is-fluid {
    max-width: none !important;
    padding-left: iv.$gap;
    padding-right: iv.$gap;
    width: 100%;
  }

  &.#{iv.$class-prefix}is-max-tablet {
    max-width: iv.$tablet - $container-offset;
  }

  @include mx.desktop {
    max-width: iv.$desktop - $container-offset;
  }

  @include mx.until-widescreen {
    &.#{iv.$class-prefix}is-widescreen:not(
        .#{iv.$class-prefix}is-max-tablet
      ):not(.#{iv.$class-prefix}is-max-desktop) {
      max-width: min(iv.$widescreen, $container-max-width) - $container-offset;
    }
  }

  @include mx.until-fullhd {
    &.#{iv.$class-prefix}is-fullhd:not(.#{iv.$class-prefix}is-max-tablet):not(
        .#{iv.$class-prefix}is-max-desktop
      ):not(.#{iv.$class-prefix}is-max-widescreen) {
      max-width: min(iv.$fullhd, $container-max-width) - $container-offset;
    }
  }

  @include mx.widescreen {
    &:not(.#{iv.$class-prefix}is-max-tablet):not(
        .#{iv.$class-prefix}is-max-desktop
      ) {
      max-width: min(iv.$widescreen, $container-max-width) - $container-offset;
    }
  }

  @include mx.fullhd {
    &:not(.#{iv.$class-prefix}is-max-tablet):not(
        .#{iv.$class-prefix}is-max-desktop
      ):not(.#{iv.$class-prefix}is-max-widescreen) {
      max-width: min(iv.$fullhd, $container-max-width) - $container-offset;
    }
  }
}
